package com.example.web;

import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.jdbc.core.RowMapper;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import javax.annotation.PostConstruct;
import javax.sql.DataSource;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.time.Instant;
import java.util.List;

@Controller
public class CommentController {

    private final JdbcTemplate jdbcTemplate;

    public CommentController(DataSource dataSource) {
        this.jdbcTemplate = new JdbcTemplate(dataSource);
    }

    @PostConstruct
    public void ensureTableExists() {
        jdbcTemplate.execute(
                "CREATE TABLE IF NOT EXISTS comments (" +
                        "id BIGINT PRIMARY KEY GENERATED ALWAYS AS IDENTITY, " +
                        "author VARCHAR(100) NOT NULL, " +
                        "body CLOB NOT NULL, " +
                        "created_at TIMESTAMP NOT NULL" +
                        ")"
        );
    }

    @GetMapping("/comments")
    public String showComments(Model model) {
        List<Comment> comments = jdbcTemplate.query(
                "SELECT id, author, body, created_at FROM comments ORDER BY created_at DESC",
                new CommentRowMapper()
        );
        model.addAttribute("comments", comments);
        return "comments";
    }

    public static class Comment {
        private long id;
        private String author;
        private String body;
        private Instant createdAt;

        public Comment() {}

        public Comment(long id, String author, String body, Instant createdAt) {
            this.id = id;
            this.author = author;
            this.body = body;
            this.createdAt = createdAt;
        }

        public long getId() {
            return id;
        }

        public void setId(long id) {
            this.id = id;
        }

        public String getAuthor() {
            return author;
        }

        public void setAuthor(String author) {
            this.author = author;
        }

        public String getBody() {
            return body;
        }

        public void setBody(String body) {
            this.body = body;
        }

        public Instant getCreatedAt() {
            return createdAt;
        }

        public void setCreatedAt(Instant createdAt) {
            this.createdAt = createdAt;
        }
    }

    private static class CommentRowMapper implements RowMapper<Comment> {
        @Override
        public Comment mapRow(ResultSet rs, int rowNum) throws SQLException {
            Instant created = rs.getTimestamp("created_at").toInstant();
            return new Comment(
                    rs.getLong("id"),
                    rs.getString("author"),
                    rs.getString("body"),
                    created
            );
        }
    }
}